# Assign service-specific roles in Bicep
// storageRoles.bicep
param storageAccountId string
param appPrincipalId string

// Storage Blob Data Contributor
var blobContributorRoleId = 'ba92f5b4-2d11-453d-a403-e96b0029c9fe'

resource blobRoleAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(storageAccountId, appPrincipalId, blobContributorRoleId)
  scope: storageAccount
  properties: {
    roleDefinitionId: subscriptionResourceId('Microsoft.Authorization/roleDefinitions', blobContributorRoleId)
    principalId: appPrincipalId
    principalType: 'ServicePrincipal'
  }
}

# Terraform: assign Key Vault Secrets User to a managed identity
data "azurerm_role_definition" "kv_secrets_user" {
  name = "Key Vault Secrets User"
}

resource "azurerm_role_assignment" "app_kv_secrets" {
  scope                = azurerm_key_vault.main.id
  role_definition_name = "Key Vault Secrets User"
  principal_id         = azurerm_user_assigned_identity.app.principal_id
}

# Output: role definition IDs for common service-specific roles
